mapper.insert:
/*
     SQL ID : SysFileDAO.insert
     설  명 : 파일 정보 등록
 */
INSERT INTO TB_LMS_ATFL (
       FILE_ID
     , FILENM
     , FILE_SAVENM
     , FILE_PATH
     , FILE_EXTNM
     , FILE_SIZE
     , FILE_TYCD
     , ORG_ID
     , ATFL_REPO_ID
     , ATFL_REPO_PATH
     , MIME_TYCD
     , INQ_CNT
     , LST_INQ_DTTM
     , RGTR_ID
     , FRST_INQ_DTTM
     , ATCL_ID
     , ETCINFO1
     , ETCINFO2
     , ETCINFO3
     , THMB_FILE_PATH
) VALUES (
       #{fileSn}
     , #{fileNm}
     , #{fileSaveNm}
     , #{filePath}
     , #{fileExt}
     , #{fileSize}
     , #{fileType}
     , NVL(#{orgId}, '-')
     , #{repoCd}
     , #{repoPath}
     , #{mimeType}
     , #{inqCnt}
     , #{lastInqDttm}
     , #{rgtrId}
     , FN_DTTM()
     , #{fileBindDataSn}
     , #{etcInfo1}
     , #{etcInfo2}
     , #{etcInfo3}
     , #{THMB_FILE_PATH}
)

mapper.update:
/*
     SQL ID : SysFileDAO.updateFileBindData
     설  명 : 파일 바인딩 정보 수정
 */
UPDATE TB_LMS_ATFL
   SET ATCL_ID  = #{fileBindDataSn}
     , ETCINFO1 = #{etcInfo1}
     , ETCINFO2 = #{etcInfo2}
     , ETCINFO3 = #{etcInfo3}
 WHERE FILE_ID = #{fileSn}

/*
     SQL ID : SysFileDAO.updateFileBindData
     설  명 : 파일 바인딩 정보 삭제
 */
UPDATE TB_LMS_ATFL
   SET ATCL_ID = NULL
 WHERE ATFL_REPO_ID = #{repoCd}
   AND ATCL_ID = #{fileBindDataSn}

mapper.delete:
/*
     SQL ID : SysFileDAO.delete
     설  명 : 파일 정보 삭제
 */
DELETE FROM TB_LMS_ATFL
 WHERE FILE_ID = #{fileSn}

mapper.insert:
/* SQL ID : SysFileDAO.copyFileInfoFromOrigin 설 명 : 원본 파일 정보 복사 */ INSERT INTO TB_LMS_ATFL ( FILE_ID , FILENM , FILE_SAVENM , FILE_PATH , FILE_EXTNM , FILE_SIZE , FILE_TYCD , ORG_ID , ATFL_REPO_ID , ATFL_REPO_PATH , MIME_TYCD , INQ_CNT
, RGTR_ID , FRST_INQ_DTTM , ATCL_ID , ETCINFO1 , ETCINFO2 , ETCINFO3 , THMB_FILE_PATH ) SELECT FILE_ID || LINE_NO , FILENM , FILE_SAVENM , FILE_PATH , FILE_EXTNM , FILE_SIZE , FILE_TYCD , ORG_ID , ATFL_REPO_ID , ATFL_REPO_PATH , MIME_TYCD , INQ_CNT
, RGTR_ID , FRST_INQ_DTTM , ATCL_ID , ETCINFO1 , ETCINFO2 , ETCINFO3 , THMB_FILE_PATH FROM ( SELECT ROW_NUMBER() OVER(ORDER BY (SELECT 1 FROM DUAL)) AS LINE_NO , #{fileSn} AS FILE_ID , FILENM , FILE_SAVENM , FILE_PATH , FILE_EXTNM , FILE_SIZE , 'clone' AS FILE_TYCD , #{orgId} AS ORG_ID , #{repoCd} AS ATFL_REPO_ID , ATFL_REPO_PATH , MIME_TYCD , 0 AS INQ_CNT
, RGTR_ID , FN_DTTM() AS FRST_INQ_DTTM , #{fileBindDataSn} AS ATCL_ID , ETCINFO1 , ETCINFO2 , ETCINFO3 , THMB_FILE_PATH FROM TB_LMS_ATFL WHERE 1=1
AND FILE_ID = #{copyFileSn}
AND ATCL_ID = #{copyFileBindDataSn}
) A

mapper.update:
        /*
             SQL ID : SysFileDAO.updateObjectStorageInfo
             설  명 : 오브젝트 스토리지 경로 정보 수정
         */
        UPDATE TB_LMS_ATFL
		SET OJB_STRG_PATH = #{objectStoragePath}

			, ETCINFO1 = IF(#{etcInfo1} = '', NULL, #{etcInfo1})


			, ETCINFO2 = IF(#{etcInfo2} = '', NULL, #{etcInfo2})


			, ETCINFO3 = IF(#{etcInfo3} = '', NULL, #{etcInfo3})

         WHERE FILE_ID = #{fileSn}
